import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonElement;
import com.google.gson.JsonSyntaxException;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;
import java.lang.reflect.Type;

class GsonFromJsonTest {

  private Gson gson;

  @BeforeEach
  void setUp() {
    gson = new Gson();
  }

  @Test
  void fromJson_withJsonElementAndType_returnsExpectedObject() throws Exception {
    // Arrange
    String jsonString = "{\"name\":\"test\"}";
    Type type = String.class;

    // Create a JsonElement by parsing the string using Gson's internal method
    // Using reflection to create JsonElement from jsonString
    Method parseStringToJsonElement = Gson.class.getDeclaredMethod("toJsonTree", Object.class);
    parseStringToJsonElement.setAccessible(true);
    JsonElement jsonElement = (JsonElement) parseStringToJsonElement.invoke(gson, jsonString);

    // Act
    Method fromJsonMethod = Gson.class.getDeclaredMethod("fromJson", JsonElement.class, Type.class);
    fromJsonMethod.setAccessible(true);
    Object result = fromJsonMethod.invoke(gson, jsonElement, type);

    // Assert
    assertNotNull(result);
    assertTrue(result instanceof String);
    assertEquals(jsonString, result);
  }

  @Test
  void fromJson_withNullJsonElement_returnsNull() throws Exception {
    // Arrange
    JsonElement jsonElement = null;
    Type type = String.class;

    // Act
    Method fromJsonMethod = Gson.class.getDeclaredMethod("fromJson", JsonElement.class, Type.class);
    fromJsonMethod.setAccessible(true);
    Object result = fromJsonMethod.invoke(gson, jsonElement, type);

    // Assert
    assertNull(result);
  }

  @Test
  void fromJson_withInvalidJson_throwsJsonSyntaxException() throws Exception {
    // Arrange
    String invalidJson = "invalid json";
    Type type = String.class;

    Method parseStringToJsonElement = Gson.class.getDeclaredMethod("toJsonTree", Object.class);
    parseStringToJsonElement.setAccessible(true);
    JsonElement jsonElement = (JsonElement) parseStringToJsonElement.invoke(gson, invalidJson);

    Method fromJsonMethod = Gson.class.getDeclaredMethod("fromJson", JsonElement.class, Type.class);
    fromJsonMethod.setAccessible(true);

    // Act & Assert
    try {
      fromJsonMethod.invoke(gson, jsonElement, type);
      // No exception thrown, fail the test
      fail("Expected JsonSyntaxException");
    } catch (Exception e) {
      Throwable cause = e.getCause();
      assertTrue(cause instanceof JsonSyntaxException || cause == null);
    }
  }

  @Test
  void fromJson_withComplexTypeToken_returnsExpectedObject() throws Exception {
    // Arrange
    String jsonString = "[\"one\", \"two\"]";
    TypeToken<java.util.List<String>> typeToken = new TypeToken<java.util.List<String>>() {};

    Method parseStringToJsonElement = Gson.class.getDeclaredMethod("toJsonTree", Object.class);
    parseStringToJsonElement.setAccessible(true);
    JsonElement jsonElement = (JsonElement) parseStringToJsonElement.invoke(gson, jsonString);

    Method fromJsonMethod = Gson.class.getDeclaredMethod("fromJson", JsonElement.class, Type.class);
    fromJsonMethod.setAccessible(true);

    // Act
    Object result = fromJsonMethod.invoke(gson, jsonElement, typeToken.getType());

    // Assert
    assertNotNull(result);
    assertTrue(result instanceof java.util.List);
    @SuppressWarnings("unchecked")
    java.util.List<String> list = (java.util.List<String>) result;
    assertEquals(2, list.size());
    assertEquals("one", list.get(0));
    assertEquals("two", list.get(1));
  }
}
